SELECT n.*, e.EMPLOYEE_NAME AS writerName, d.DEPT_NAME AS writerDeptName FROM NOTICE n JOIN EMPLOYEE e ON n.WRITER_ID = e.EMPLOYEE_ID LEFT JOIN DEPARTMENT d ON e.DEPT_ID = d.DEPT_ID
