ORDER BY n.IS_PINNED DESC, n.NOTICE_ID DESC LIMIT #{size} OFFSET #{offset}
SELECT COUNT(*) FROM NOTICE n
n.NOTICE_TITLE LIKE CONCAT('%', #{keyword}, '%') OR n.NOTICE_CONTENT LIKE CONCAT('%', #{keyword}, '%')
SELECT n.*, e.EMPLOYEE_NAME AS writerName, d.DEPT_NAME AS writerDeptName FROM NOTICE n JOIN EMPLOYEE e ON n.WRITER_ID = e.EMPLOYEE_ID LEFT JOIN DEPARTMENT d ON e.DEPT_ID = d.DEPT_ID WHERE n.NOTICE_ID = #{noticeId}
UPDATE NOTICE SET VIEW_COUNT = VIEW_COUNT + 1 WHERE NOTICE_ID = #{noticeId}
SELECT n.*, e.EMPLOYEE_NAME AS writerName, d.DEPT_NAME AS writerDeptName FROM NOTICE n JOIN EMPLOYEE e ON n.WRITER_ID = e.EMPLOYEE_ID LEFT JOIN DEPARTMENT d ON e.DEPT_ID = d.DEPT_ID WHERE n.NOTICE_ID = #{noticeId}
INSERT INTO NOTICE (WRITER_ID, NOTICE_TITLE, NOTICE_CONTENT, IS_PINNED) VALUES (#{writerId}, #{noticeTitle}, #{noticeContent}, #{isPinned})
UPDATE NOTICE SET NOTICE_TITLE = #{noticeTitle}, NOTICE_CONTENT = #{noticeContent}, IS_PINNED = #{isPinned}, UPDATED_AT = NOW() WHERE NOTICE_ID = #{noticeId}
DELETE FROM NOTICE WHERE NOTICE_ID = #{noticeId}
